+import { ComponentFixture, TestBed } from "@angular/core/testing";
+import { BehaviorSubject, Subject } from "rxjs";
+import { beforeEach, describe, expect, it, vi } from "vitest";
+import { signal, WritableSignal } from "@angular/core";
+
+import { DrawingIndexPanelComponent } from "./drawing-index-panel.component";
+import { DRAWING_INDEX_PANEL_QA } from "./drawing-index-panel-qa";
+import { DrawingIndexPanelService } from "../../services/drawing-index-panel.service";
+import { DrawingGroup } from "../../classes/DrawingGroup";
+import { DrawingItem } from "../../classes/DrawingItem";
+import { IDrawingModule } from "../../interfaces/IDrawingModule";
+
+import { ComponentSettingsService } from "../../../shared/services/ComponentSettingsService";
+import { configureStandalonePageTest } from "../../../shared/testing/configure-standalone-page-test";
+import { detectChangesAndWhenStable } from "../../../shared/testing/detect-changes-helpers";
+import { qaDom, TEST_DOM_STABLE_ID_ATTRIBUTE, type QaDom } from "../../../shared/testing/by-qa-id";
+
+declare global {
+    interface Window {
+        DrawingModule?: IDrawingModule;
+    }
+}
+
+function createMockNomenclature() {
+    return {
+        drawings: "Drawings",
+        closeSearch: "Close search",
+        search: "Search",
+        closePanel: "Close panel",
+        clear: "Clear",
+        collapse: "Collapse",
+        expand: "Expand",
+        noResultsLine1: "No results found",
+        noResultsLine2: "Check spelling or try a different word.",
+        successfullyProcessed: "Successfully processed",
+        missingProperties: "Action required",
+        actionRequired_title: "Title is missing",
+        actionRequired_number: "Number is missing",
+        actionRequired_both: "Number is missing<br>Title is missing",
+    };
+}
+
+function createMockDrawingIndexPanelService() {
+    const detectChangesSubject = new Subject();
+    return {
+        selectedDrawingId: signal(0) as WritableSignal<number>,
+        nomenclature: signal(createMockNomenclature()),
+        visibleDrawingCount: signal(5),
+        itemsOrGroups: signal<(DrawingItem | DrawingGroup)[]>([]),
+        isGrouping: signal(false),
+        foundItems: signal<DrawingItem[]>([]),
+        detectChangesNeededEvent: detectChangesSubject.asObservable(),
+        init: vi.fn(),
+        search: vi.fn(),
+        searchCancelled: vi.fn(),
+        propertiesHaveChanged: vi.fn(),
+        updateDuplicateErrorFlag: vi.fn(),
+        _detectChangesSubject: detectChangesSubject,
+    };
+}
+
+function createMockDrawingModule(): IDrawingModule {
+    return {
+        getDrawingSeriesId: vi.fn(),
+        addHandler: vi.fn(),
+        toggleDrawingIndexPanel: vi.fn(),
+        onDrawingSelected: vi.fn(),
+        closeDrawingLayerPanel: vi.fn(),
+        setAnnotationChangeFlag: vi.fn(),
+        DWGEVENT_LOADING_FINISHED: "loadingFinished",
+    } as IDrawingModule;
+}
+
+function createDrawingItem(overrides: Partial<DrawingItem> = {}): DrawingItem {
+    return {
+        drawingid: 1,
+        number: "A6.01",
+        title: "ELEVATOR CORE PLANS",
+        ...overrides,
+    } as DrawingItem;
+}
+
+function createDrawingGroup(name: string, options: { isOpen?: boolean; drawings?: DrawingItem[] } = {}): DrawingGroup {
+    const { isOpen = false, drawings = [createDrawingItem()] } = options;
+
+    const group = new DrawingGroup(name);
+    group.isOpen = isOpen;
+    group.drawings = drawings;
+
+    return group;
+}
+
+describe("DrawingIndexPanelComponent", () => {
+    let fixture: ComponentFixture<DrawingIndexPanelComponent>;
+    let component: DrawingIndexPanelComponent;
+    let mockService: ReturnType<typeof createMockDrawingIndexPanelService>;
+
+    async function configureModule(renderTemplate: boolean): Promise<void> {
+        TestBed.resetTestingModule();
+
+        window.DrawingModule = createMockDrawingModule();
+        mockService = createMockDrawingIndexPanelService();
+
+        const result = await configureStandalonePageTest(DrawingIndexPanelComponent, {
+            renderTemplate,
+            providers: [
+                { provide: DrawingIndexPanelService, useValue: mockService },
+                { provide: ComponentSettingsService, useValue: { settings$: new BehaviorSubject({}).asObservable() } },
+            ],
+        });
+
+        fixture = result.fixture;
+        component = result.component;
+    }
+
+    /** Stubs the `@ViewChild("searchInput")` element so search-related logic can run without the real DOM input. */
+    function stubSearchInput(value: string): void {
+        component["_searchInput"] = { nativeElement: { value, focus: vi.fn() } };
+    }
+
+    /** Sets the service into flat-list mode with the given items and flushes change detection. */
+    function renderItems(items: DrawingItem[]): void {
+        mockService.itemsOrGroups.set(items);
+        mockService.isGrouping.set(false);
+        fixture.detectChanges();
+    }
+
+    /** Sets the service into grouped mode with the given groups and flushes change detection. */
+    function renderGroups(...groups: DrawingGroup[]): void {
+        mockService.itemsOrGroups.set(groups);
+        mockService.isGrouping.set(true);
+        fixture.detectChanges();
+    }
+
+    describe("Business Logic", () => {
+        beforeEach(async () => {
+            await configureModule(false);
+            await detectChangesAndWhenStable(fixture, true);
+        });
+
+        it("should create", () => {
+            expect(component).toBeTruthy();
+        });
+
+        it("hide() sets visible to false", () => {
+            component.show();
+            component.hide();
+
+            expect(component["visible"]()).toBe(false);
+        });
+
+        it("isVisible() returns current visible signal value", () => {
+            expect(component.isVisible()).toBe(false);
+
+            component.show();
+
+            expect(component.isVisible()).toBe(true);
+        });
+
+        it("toggleVisible() flips visible signal", () => {
+            expect(component["visible"]()).toBe(false);
+
+            component.toggleVisible();
+            expect(component["visible"]()).toBe(true);
+
+            component.toggleVisible();
+            expect(component["visible"]()).toBe(false);
+        });
+
+        it("init() calls service.init with correct arguments", () => {
+            const drawings = [{ drawingid: 1 }, { drawingid: 2 }];
+            component.init(drawings, 1, "discipline");
+
+            expect(mockService.init).toHaveBeenCalledWith(drawings, 1, "discipline");
+        });
+
+        it("init() sets _loading true; scroll timer clears it after 250ms", () => {
+            vi.useFakeTimers();
+            try {
+                component.init([{ drawingid: 1 }], 1, "discipline");
+                expect(component["_loading"]).toBe(true);
+
+                // Make 250 milliseconds pass to trigger the loading wait
+                vi.advanceTimersByTime(250);
+                expect(component["_loading"]).toBe(false);
+            } finally {
+                vi.useRealTimers();
+            }
+        });
+
+        it("closePanel() calls DrawingModule.toggleDrawingIndexPanel", () => {
+            component["closePanel"]();
+
+            expect(window.DrawingModule!.toggleDrawingIndexPanel).toHaveBeenCalled();
+        });
+
+        it("closePanel() does nothing when DrawingModule is undefined", () => {
+            window.DrawingModule = undefined;
+
+            expect(() => component["closePanel"]()).not.toThrow();
+        });
+
+        it("selectDrawing() calls DrawingModule.onDrawingSelected with drawingId and callback", () => {
+            component.selectDrawing(42);
+
+            expect(window.DrawingModule!.onDrawingSelected).toHaveBeenCalledWith(42, expect.any(Function));
+        });
+
+        it("selectDrawing() does nothing when DrawingModule is undefined", () => {
+            window.DrawingModule = undefined;
+
+            expect(() => component.selectDrawing(42)).not.toThrow();
+        });
+
+        it("drawingSelected() sets service.selectedDrawingId", () => {
+            component["drawingSelected"](99);
+
+            expect(mockService.selectedDrawingId()).toBe(99);
+        });
+
+        it("toggleGroup() flips group.isOpen", () => {
+            const group = new DrawingGroup("Test Group");
+            expect(group.isOpen).toBe(false);
+
+            component["toggleGroup"](group);
+            expect(group.isOpen).toBe(true);
+
+            component["toggleGroup"](group);
+            expect(group.isOpen).toBe(false);
+        });
+
+        it("toggleSearch() does nothing when _loading is true", () => {
+            component["_loading"] = true;
+            
+            component["toggleSearch"]();
+
+            expect(component["isSearching"]()).toBe(false);
+        });
+
+        it("toggleSearch() enables search mode when not loading", () => {
+            component["_loading"] = false;
+            stubSearchInput("");
+
+            component["toggleSearch"]();
+
+            expect(component["isSearching"]()).toBe(true);
+        });
+
+        it("toggleSearch() disables search mode and calls searchCancelled", () => {
+            component["_loading"] = false;
+            stubSearchInput("");
+            component["toggleSearch"](); // enable
+
+            component["toggleSearch"](); // disable
+
+            expect(component["isSearching"]()).toBe(false);
+            expect(mockService.searchCancelled).toHaveBeenCalled();
+        });
+
+        it("searchInputFocus() sets searchFocused signal", () => {
+            component["searchInputFocus"](true);
+            expect(component["searchFocused"]()).toBe(true);
+
+            component["searchInputFocus"](false);
+            expect(component["searchFocused"]()).toBe(false);
+        });
+
+        it("cancelSearch() sets isSearching to false and calls searchCancelled", () => {
+            component["_loading"] = false;
+            stubSearchInput("");
+            component["toggleSearch"]();
+
+            component.cancelSearch();
+
+            expect(component["isSearching"]()).toBe(false);
+            expect(mockService.searchCancelled).toHaveBeenCalled();
+        });
+
+        it("search() passes lowercased, trimmed input value to service.search", () => {
+            stubSearchInput("  ELEVATOR  ");
+
+            component["search"]();
+
+            expect(mockService.search).toHaveBeenCalledWith("elevator");
+        });
+
+        it("needLazyLoading() returns false when count is 2500", () => {
+            expect(component.needLazyLoading(2500)).toBe(false);
+        });
+
+        it("needLazyLoading() returns true when count is 2501", () => {
+            expect(component.needLazyLoading(2501)).toBe(true);
+        });
+
+        it("needLazyLoading() returns false when count is 0", () => {
+            expect(component.needLazyLoading(0)).toBe(false);
+        });
+
+        it("ngOnInit subscribes to detectChangesNeededEvent", () => {
+            const cdSpy = vi.spyOn(component["_cd"], "detectChanges");
+
+            mockService._detectChangesSubject.next(true);
+
+            expect(cdSpy).toHaveBeenCalled();
+        });
+    });
+
+    describe("UI render test", () => {
+        let qa: QaDom<DrawingIndexPanelComponent>;
+
+        beforeEach(async () => {
+            await configureModule(true);
+            component.show();
+            await detectChangesAndWhenStable(fixture, true);
+            qa = qaDom(fixture);
+        });
+
+        it("panel root has correct gainsightId", () => {
+            const el = qa.query(DRAWING_INDEX_PANEL_QA.panelRoot);
+
+            expect(el).toBeTruthy();
+            expect(el!.nativeElement.getAttribute(TEST_DOM_STABLE_ID_ATTRIBUTE)).toBe(DRAWING_INDEX_PANEL_QA.panelRoot);
+        });
+
+        it("panel is hidden when visible() is false", () => {
+            component.hide();
+            fixture.detectChanges();
+
+            const el = qa.query(DRAWING_INDEX_PANEL_QA.panelRoot);
+            
+            expect(el!.nativeElement.hidden).toBe(true);
+        });
+
+        it("title shows drawings nomenclature and count", () => {
+            const titleText = qa.text(DRAWING_INDEX_PANEL_QA.panelTitle);
+
+            expect.soft(titleText).toContain("Drawings");
+            expect.soft(titleText).toContain("(5)");
+        });
+
+        it("title bar is hidden and search bar is shown when searching", () => {
+            component["_loading"] = false;
+            component["isSearching"].set(true);
+            fixture.detectChanges();
+
+            const titleBar = qa.query(DRAWING_INDEX_PANEL_QA.titleBar);
+            const searchBar = qa.query(DRAWING_INDEX_PANEL_QA.searchBar);
+
+            expect.soft(titleBar!.nativeElement.hidden).toBe(true);
+            expect.soft(searchBar!.nativeElement.hidden).toBe(false);
+        });
+
+        it("clicking search icon enables search mode", async () => {
+            component["_loading"] = false;
+            stubSearchInput("");
+
+            qa.click(DRAWING_INDEX_PANEL_QA.searchIcon);
+
+            expect(component["isSearching"]()).toBe(true);
+        });
+
+        it("clicking close icon calls DrawingModule.toggleDrawingIndexPanel", () => {
+            qa.click(DRAWING_INDEX_PANEL_QA.closeIcon);
+
+            expect(window.DrawingModule!.toggleDrawingIndexPanel).toHaveBeenCalled();
+        });
+
+        it("clicking search back icon disables search mode", () => {
+            component["_loading"] = false;
+            component["isSearching"].set(true);
+            fixture.detectChanges();
+
+            qa.click(DRAWING_INDEX_PANEL_QA.searchBackIcon);
+
+            expect.soft(component["isSearching"]()).toBe(false);
+            expect.soft(mockService.searchCancelled).toHaveBeenCalled();
+        });
+
+        it("search container gets search-active class when focused", () => {
+            component["_loading"] = false;
+            component["isSearching"].set(true);
+            component["searchFocused"].set(true);
+            fixture.detectChanges();
+
+            const el = qa.query(DRAWING_INDEX_PANEL_QA.searchContainer);
+
+            expect(el!.nativeElement.classList).toContain("search-active");
+        });
+
+        it("renders drawing items when not searching and not grouping", () => {
+            renderItems([createDrawingItem({ drawingid: 1 }), createDrawingItem({ drawingid: 2 })]);
+
+            const drawingItems = qa.queryAll(DRAWING_INDEX_PANEL_QA.drawingItem);
+
+            expect(drawingItems.length).toBe(2);
+        });
+
+        it("renders group header with name and count when grouping", () => {
+            const drawingGroup = createDrawingGroup("Mechanical", { drawings: [createDrawingItem(), createDrawingItem({ drawingid: 2 })] });
+            renderGroups(drawingGroup);
+
+            const groupHeaderText = qa.text(DRAWING_INDEX_PANEL_QA.groupHeader);
+
+            expect.soft(groupHeaderText).toContain("Mechanical");
+            expect.soft(groupHeaderText).toContain("(2)");
+        });
+
+        it("group arrow shows chevron-down when group is closed", () => {
+            const drawingGroup = createDrawingGroup("Test", { isOpen: false });
+            renderGroups(drawingGroup);
+
+            const arrow = qa.query(DRAWING_INDEX_PANEL_QA.groupArrow);
+
+            expect.soft(arrow!.nativeElement.classList).toContain("fa-chevron-down");
+            expect.soft(arrow!.nativeElement.classList).not.toContain("fa-chevron-up");
+        });
+
+        it("group arrow shows chevron-up when group is open", () => {
+            const drawingGroup = createDrawingGroup("Test", { isOpen: true });
+            renderGroups(drawingGroup);
+
+            const arrow = qa.query(DRAWING_INDEX_PANEL_QA.groupArrow);
+
+            expect.soft(arrow!.nativeElement.classList).toContain("fa-chevron-up");
+            expect.soft(arrow!.nativeElement.classList).not.toContain("fa-chevron-down");
+        });
+
+        it("drawing items in closed group are hidden", () => {
+            const drawingGroup = createDrawingGroup("Test", { isOpen: false });
+            renderGroups(drawingGroup);
+
+            const drawingItem = qa.query(DRAWING_INDEX_PANEL_QA.drawingItem);
+
+            expect(drawingItem!.nativeElement.hidden).toBe(true);
+        });
+
