+import { ComponentFixture, TestBed } from "@angular/core/testing";
+import { BehaviorSubject, Subject } from "rxjs";
+import { beforeEach, describe, expect, it, vi } from "vitest";
+import { signal, WritableSignal } from "@angular/core";
+
+import { DrawingIndexPanelComponent } from "./drawing-index-panel.component";
+import { DRAWING_INDEX_PANEL_QA } from "./drawing-index-panel-qa";
+import { DrawingIndexPanelService } from "../../services/drawing-index-panel.service";
+import { DrawingGroup } from "../../classes/DrawingGroup";
+import { DrawingItem } from "../../classes/DrawingItem";
+import { IDrawingModule } from "../../interfaces/IDrawingModule";
+
+import { ComponentSettingsService } from "../../../shared/services/ComponentSettingsService";
+import { configureStandalonePageTest } from "../../../shared/testing/configure-standalone-page-test";
+import { detectChangesAndWhenStable } from "../../../shared/testing/detect-changes-helpers";
+import { qaDom, TEST_DOM_STABLE_ID_ATTRIBUTE, type QaDom } from "../../../shared/testing/by-qa-id";
+
+declare global {
+    interface Window {
+        DrawingModule?: IDrawingModule;
+    }
+}
+
+function createMockNomenclature() {
+    return {
+        drawings: "Drawings",
+        closeSearch: "Close search",
+        search: "Search",
+        closePanel: "Close panel",
+        clear: "Clear",
+        collapse: "Collapse",
+        expand: "Expand",
+        noResultsLine1: "No results found",
+        noResultsLine2: "Check spelling or try a different word.",
+        successfullyProcessed: "Successfully processed",
+        missingProperties: "Action required",
+        actionRequired_title: "Title is missing",
+        actionRequired_number: "Number is missing",
+        actionRequired_both: "Number is missing<br>Title is missing",
+    };
+}
+
+function createMockDrawingIndexPanelService() {
+    const detectChangesSubject = new Subject();
+    return {
+        selectedDrawingId: signal(0) as WritableSignal<number>,
+        nomenclature: signal(createMockNomenclature()),
+        visibleDrawingCount: signal(5),
+        itemsOrGroups: signal<(DrawingItem | DrawingGroup)[]>([]),
+        isGrouping: signal(false),
+        foundItems: signal<DrawingItem[]>([]),
+        detectChangesNeededEvent: detectChangesSubject.asObservable(),
+        init: vi.fn(),
+        search: vi.fn(),
+        searchCancelled: vi.fn(),
+        propertiesHaveChanged: vi.fn(),
+        updateDuplicateErrorFlag: vi.fn(),
+        _detectChangesSubject: detectChangesSubject,
+    };
+}
+
+function createMockDrawingModule(): IDrawingModule {
+    return {
+        getDrawingSeriesId: vi.fn(),
+        addHandler: vi.fn(),
+        toggleDrawingIndexPanel: vi.fn(),
+        onDrawingSelected: vi.fn(),
+        closeDrawingLayerPanel: vi.fn(),
+        setAnnotationChangeFlag: vi.fn(),
+        DWGEVENT_LOADING_FINISHED: "loadingFinished",
+    } as IDrawingModule;
+}
+
+function createDrawingItem(overrides: Partial<DrawingItem> = {}): DrawingItem {
+    return {
+        drawingid: 1,
+        number: "A6.01",
+        title: "ELEVATOR CORE PLANS",
+        ...overrides,
+    } as DrawingItem;
+}
+
+function createDrawingGroup(name: string, options: { isOpen?: boolean; drawings?: DrawingItem[] } = {}): DrawingGroup {
+    const { isOpen = false, drawings = [createDrawingItem()] } = options;
+
+    const group = new DrawingGroup(name);
+    group.isOpen = isOpen;
+    group.drawings = drawings;
+
+    return group;
+}
+
+describe("DrawingIndexPanelComponent", () => {
+    let fixture: ComponentFixture<DrawingIndexPanelComponent>;
+    let component: DrawingIndexPanelComponent;
+    let mockService: ReturnType<typeof createMockDrawingIndexPanelService>;
+
+    async function configureModule(renderTemplate: boolean): Promise<void> {
+        TestBed.resetTestingModule();
+
+        window.DrawingModule = createMockDrawingModule();
+        mockService = createMockDrawingIndexPanelService();
+
+        const result = await configureStandalonePageTest(DrawingIndexPanelComponent, {
+            renderTemplate,
+            providers: [
+                { provide: DrawingIndexPanelService, useValue: mockService },
+                { provide: ComponentSettingsService, useValue: { settings$: new BehaviorSubject({}).asObservable() } },
+            ],
+        });
+
+        fixture = result.fixture;
+        component = result.component;
+    }
+
+    /** Stubs the `@ViewChild("searchInput")` element so search-related logic can run without the real DOM input. */
+    function stubSearchInput(value: string): void {
+        component["_searchInput"] = { nativeElement: { value, focus: vi.fn() } };
+    }
+
+    /** Sets the service into flat-list mode with the given items and flushes change detection. */
+    function renderItems(items: DrawingItem[]): void {
+        mockService.itemsOrGroups.set(items);
+        mockService.isGrouping.set(false);
+        fixture.detectChanges();
+    }
+
+    /** Sets the service into grouped mode with the given groups and flushes change detection. */
+    function renderGroups(...groups: DrawingGroup[]): void {
+        mockService.itemsOrGroups.set(groups);
+        mockService.isGrouping.set(true);
+        fixture.detectChanges();
+    }
+
+    describe("Business Logic", () => {
+        beforeEach(async () => {
+            await configureModule(false);
+            await detectChangesAndWhenStable(fixture, true);
+        });
+
+        it("should create", () => {
+            expect(component).toBeTruthy();
+        });
+
+        it("hide() sets visible to false", () => {
+            component.show();
+            component.hide();
+
+            expect(component["visible"]()).toBe(false);
+        });
+
+        it("isVisible() returns current visible signal value", () => {
+            expect(component.isVisible()).toBe(false);
+
+            component.show();
+
+            expect(component.isVisible()).toBe(true);
+        });
+
+        it("toggleVisible() flips visible signal", () => {
+            expect(component["visible"]()).toBe(false);
+
+            component.toggleVisible();
+            expect(component["visible"]()).toBe(true);
+
+            component.toggleVisible();
+            expect(component["visible"]()).toBe(false);
+        });
